-- Luke Chapter 10
-- Theme: Mission, Mercy, and Contemplation — The Kingdom Advances Through Word, Deed, and Devotion
-- 42 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 10,
  'Luke 10 is one of the richest chapters in the entire Gospel, containing three of the most theologically significant units in Luke''s Travel Narrative. The chapter opens with the commissioning of seventy (or seventy-two) additional disciples — a doubling of the missionary force that signals the kingdom''s expanding advance. Their mission brief echoes the Twelve''s commission (9:1-6) but with sharper urgency: the harvest is plentiful, the labourers are few, the time is short. The woes on Chorazin, Bethsaida, and Capernaum (vv.13-16) reveal the gravity of rejecting the kingdom — greater culpability than Tyre, Sidon, or Sodom.' ||
  'The return of the seventy (vv.17-24) is one of the most joyful passages in the Gospels. They report with amazement that "even the devils are subject unto us through thy name." Jesus responds with a vision of cosmic significance: he saw Satan fall like lightning from heaven. The successful mission anticipates the full defeat of the enemy at the cross. Yet Jesus immediately redirects their joy: "rejoice not that the spirits are subject unto you; but rather rejoice, because your names are written in heaven." The chapter''s theology of joy is grounded not in successful ministry performance but in the security of belonging to God.' ||
  'The parable of the Good Samaritan (vv.25-37) is Luke''s most famous parable and one of the most influential stories in human history. It arises from a lawyer''s question about eternal life and his follow-up question "Who is my neighbour?" Jesus inverts the question: instead of asking who qualifies as my neighbour (thereby defining the limits of obligation), the parable asks what it means to be a neighbour. The Samaritan — the despised outcast who had every cultural reason to pass by — embodies the love that crosses every boundary. "Go, and do thou likewise" is the shortest and most demanding sermon in the Gospel.' ||
  'The chapter closes with the Mary and Martha episode (vv.38-42) — another unit unique to Luke. The contrast between the two sisters provides the final theological word of the chapter: the "good part" that will not be taken away is not service (however essential), but sitting at Jesus''s feet and hearing his word. After the chapter''s intense emphasis on active mission, the contemplative posture of Mary is presented as the necessary foundation of all service. Word and deed, hearing and doing — both belong together in Luke''s portrait of the kingdom disciple.',
  'Mission, Mercy, and Contemplation — The Kingdom Advances Through Word, Deed, and Devotion',
  'πλησίον (plēsion)',
  'plēsion means neighbor, one who is near. In the parable of the Good Samaritan, Jesus transforms the static noun (who is my neighbor — defined by geographic or ethnic proximity) into a dynamic question (which of these three proved to be a neighbor — defined by compassionate action). The neighbor is not the person geographically nearest but the one who acts with mercy toward a person in need. This redefinition demolishes all ethnic, religious, and social barriers to the obligation of love.',
  '["The Mission of the Seventy: Harvest Urgency and Kingdom Authority (vv.1-16)","The Return of the Seventy: Cosmic Victory and the Joy of Belonging (vv.17-24)","The Good Samaritan: Who Is My Neighbour? (vv.25-37)","Mary and Martha: The One Thing Needful (vv.38-42)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'After these things the Lord appointed other seventy also, and sent them two and two before his face into every city and place, whither he himself would come.', 'Μετὰ δὲ ταῦτα ἀνέδειξεν ὁ Κύριος καὶ ἑτέρους ἑβδομήκοντα, καὶ ἀπέστειλεν αὐτοὺς ἀνὰ δύο πρὸ προσώπου αὐτοῦ εἰς πᾶσαν πόλιν καὶ τόπον οὗ ἤμελλεν αὐτὸς ἔρχεσθαι.', 'Meta de tauta anedeixe ho Kurios kai heterous hebdomēkonta, kai apesteilen autous ana duo pro prosōpou autou eis pasan polin kai topon hou ēmellen autos erchesthai.', '"Seventy" (or seventy-two in some manuscripts) — most likely echoing the seventy elders of Israel (Num 11:16-17,24-25) and/or the seventy nations of Genesis 10 (LXX has 72), symbolizing both the breadth of Israel''s leadership and the universal reach of the mission. "Two and two" (ana duo) — pairs provide mutual support, accountability, and the two-witness authentication. "Before his face" — they are advance parties for Jesus''s own coming, as the messenger before the Lord (7:27).', NULL),
  (2, 'Therefore said he unto them, The harvest truly is great, but the labourers are few: pray ye therefore the Lord of the harvest, that he would send forth labourers into his harvest.', 'ἔλεγεν δὲ πρὸς αὐτούς, Ὁ μὲν θερισμὸς πολύς, οἱ δὲ ἐργάται ὀλίγοι· δεήθητε οὖν τοῦ κυρίου τοῦ θερισμοῦ ὅπως ἐκβάλῃ ἐργάτας εἰς τὸν θερισμὸν αὐτοῦ.', 'elegen de pros autous, Ho men therismos polus, hoi de ergatai oligoi; deēthēte oun tou kuriou tou therismou hopōs ekbalē ergatas eis ton herismon autou.', '"The harvest truly is great" — the metaphor of harvest communicates both urgency and abundance. The fields are white with grain (cf. John 4:35); the grain will perish if not reaped at the right moment. "The Lord of the harvest" (ton kurion tou therismou) — God himself owns the harvest and authorizes the workers. The disciples are to pray for more workers — not to work harder themselves (though they must), but to pray for more to be sent. The harvest exceeds any one team''s capacity.', NULL),
  (3, 'Go your ways: behold, I send you forth as lambs among wolves.', 'ὑπάγετε· ἰδοὺ ἀποστέλλω ὑμᾶς ὡς ἄρνας ἐν μέσῳ λύκων.', 'hupagete; idou apostellō humas hōs arnas en mesō lukōn.', '"Lambs among wolves" — a stark image of vulnerability and danger. The disciples are not sent as lions but as lambs. The power of their mission is not self-generated strength but the authority of the one who sends them. The image also anticipates the cross: the Lamb of God himself was the ultimate lamb among wolves. Vulnerability is not a failure of mission design; it is part of its theology.', NULL),
  (4, 'Carry neither purse, nor scrip, nor shoes: and salute no man by the way.', 'μὴ βαστάζετε βαλλάντιον, μὴ πήραν, μὴ ὑποδήματα· καὶ μηδένα κατὰ τὴν ὁδὸν ἀσπάσησθε.', 'mē bastazetē ballantion, mē pēran, mē hupodēmata; kai mēdena kata tēn hodon aspasēsthe.', '"Salute no man by the way" — Eastern greetings were elaborate and time-consuming affairs that could consume hours. The urgency of the harvest does not permit extended social ritual. This is not social rudeness but eschatological urgency: the kingdom''s time-sensitive advance takes priority over customary social delay. The austerity of equipment (no purse, bag, sandals) again expresses dependence on God and the host community.', NULL),
  (5, 'And into whatsoever house ye enter, first say, Peace be to this house.', 'εἰς ἣν δ'' ἂν εἰσέλθητε οἰκίαν, πρῶτον λέγετε, Εἰρήνη τῷ οἴκῳ τούτῳ.', 'eis hēn d'' an eiselthēte oikian, prōton legete, Eirēnē tō oikō toutō.', '"Peace be to this house" (Eirēnē tō oikō toutō) — the Hebrew shalom greeting is here elevated to a performative declaration. The missionaries'' greeting is not merely a social formula but a pronouncement of divine peace that seeks a "son of peace" (v.6) to receive it. The peace of the gospel is offered first, before any teaching or miracle. Hospitality is the prerequisite for mission.', NULL),
  (6, 'And if the son of peace be there, your peace shall rest upon it: if not, it shall turn to you again.', 'καὶ ἐὰν ἐκεῖ ᾖ υἱὸς εἰρήνης, ἐπαναπαύσεται ἐπ'' αὐτὸν ἡ εἰρήνη ὑμῶν· εἰ δὲ μή γε, ἐφ'' ὑμᾶς ἀνακάμψει.', 'kai ean ekei ē huios eirēnēs, epanapausetai ep'' auton hē eirēnē humōn; ei de mē ge, eph'' humas anakampsei.', '"Son of peace" (huios eirēnēs) — a Hebraism: a person characterized by peace, ready to receive it. Peace does not simply fall on all indiscriminately; it finds those who are prepared to receive it. "Shall turn to you again" — the peace offered is not wasted; if rejected, it returns to the messenger. This means the missionaries'' own peace is not depleted by rejection — they return with the same peace they brought, ready to offer it in the next place.', NULL),
  (7, 'And in the same house remain, eating and drinking such things as they give: for the labourer is worthy of his hire. Go not from house to house.', 'ἐν αὐτῇ δὲ τῇ οἰκίᾳ μένετε, ἐσθίοντες καὶ πίνοντες τὰ παρ'' αὐτῶν· ἄξιος γὰρ ὁ ἐργάτης τοῦ μισθοῦ αὐτοῦ ἐστίν· μὴ μεταβαίνετε ἐξ οἰκίας εἰς οἰκίαν.', 'en autē de tē oikia menete, esthiontes kai pinontes ta par'' autōn; axios gar ho ergatēs tou misthou autou estin; mē metabainete ex oikias eis oikian.', '"The labourer is worthy of his hire" (axios ho ergatēs tou misthou) — cited by Paul in 1 Tim 5:18 as Scripture. The principle establishes that those who preach the gospel have a right to material support from those who benefit (1 Cor 9:14). "Go not from house to house" — stability prevents the appearance of seeking better conditions and avoids disruption of the host community. Content with initial provision, the missionary focuses on the mission.', NULL),
  (8, 'And into whatsoever city ye enter, and they receive you, eat such things as are set before you:', 'καὶ εἰς ἣν ἂν πόλιν εἰσέρχησθε, καὶ δέχωνταί ὑμᾶς, ἐσθίετε τὰ παρατιθέμενα ὑμῖν,', 'kai eis hēn an polin eiserchēsthe, kai dechōntai humas, esthiete ta paratithemena humin,', '"Eat such things as are set before you" — a significant ruling for missionaries in Gentile contexts (anticipated by Paul in 1 Cor 10:27). The missionary does not impose food laws on hosts; they eat whatever is provided with gratitude. This posture of humble acceptance counters the arrogance that might otherwise accompany a sense of religious superiority, and makes the missionary accessible to those they are sent to reach.', NULL),
  (9, 'And heal the sick that are therein, and say unto them, The kingdom of God is come nigh unto you.', 'καὶ θεραπεύετε τοὺς ἐν αὐτῇ ἀσθενεῖς, καὶ λέγετε αὐτοῖς, Ἤγγικεν ἐφ'' ὑμᾶς ἡ βασιλεία τοῦ Θεοῦ.', 'kai therapeuete tous en autē astheneis, kai legete autois, Ēngiken eph'' humas hē basileia tou Theou.', '"The kingdom of God is come nigh unto you" (ēngiken — perfect tense: has come near and remains near). The healing demonstrates the arrival of the kingdom in power; the proclamation interprets its meaning. The kingdom is not merely announced — it is enacted. The proximity of the kingdom is the reason for both the urgency and the joy. This is the evangelistic core of the mission: the kingdom has drawn near in the person of Jesus.', NULL),
  (10, 'But into whatsoever city ye enter, and they receive you not, go your ways out into the streets of the same, and say,', 'εἰς ἣν δ'' ἂν πόλιν εἰσέλθητε καὶ μὴ δέχωνταί ὑμᾶς, ἐξελθόντες εἰς τὰς πλατείας αὐτῆς εἴπατε,', 'eis hēn d'' an polin eiselthēte kai mē dechōntai humas, exelthontes eis tas plateias autēs eipate,', 'The instruction for rejection is deliberate and public: go into the streets (the public square) and make a formal declaration. Rejection does not mean silent withdrawal; it means a public testimony that the offer was made and refused. This protects both the missionaries (from indefinite labor in unreceptive soil) and the city (from the false impression that no warning was given).', NULL),
  (11, 'Even the very dust of your city, which cleaveth on us, we do wipe off against you: notwithstanding be ye sure of this, that the kingdom of God is come nigh unto you.', 'Καὶ τὸν κονιορτὸν τὸν κολληθέντα ἡμῖν ἐκ τῆς πόλεως ὑμῶν ἀπομασσόμεθα ὑμῖν· πλὴν τοῦτο γινώσκετε, ὅτι ἤγγικεν ἡ βασιλεία τοῦ Θεοῦ.', 'Kai ton koniorton ton kollēthenta hēmin ek tēs poleōs humōn apomassometha humin; plēn touto ginōskete, hoti ēngiken hē basileia tou Theou.', 'Even in rejection, the kingdom''s nearness is re-declared: "notwithstanding be ye sure of this" — the rejected city is left with no excuse. The dust-shaking (echoing 9:5) combined with the re-proclamation of kingdom nearness is a paradox: we leave, but we leave you with the truth we came to bring. The offer stands; the consequences of rejection also stand.', NULL),
  (12, 'But I say unto you, that it shall be more tolerable in that day for Sodom, than for that city.', 'λέγω ὑμῖν ὅτι Σοδόμοις ἐν τῇ ἡμέρᾳ ἐκείνῃ ἀνεκτότερον ἔσται ἢ τῇ πόλει ἐκείνῃ.', 'legō humin hoti Sodomois en tē hēmera ekeinē anektoteron estai ē tē polei ekeinē.', '"More tolerable for Sodom" — Sodom was the archetype of wickedness destroyed by divine judgment (Gen 19). Yet Sodom never had the gospel; cities that reject the seventy have had the kingdom brought to their door. Greater privilege creates greater accountability. "In that day" — the eschatological judgment day. The comparative "more tolerable" (anektoteron) implies degrees of punishment in final judgment, a principle consistently affirmed in Luke''s eschatological teaching.', NULL),
  (13, 'Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works had been done in Tyre and Sidon, which have been done in you, they had a great while ago repented, sitting in sackcloth and ashes.', 'Οὐαί σοι, Χοραζίν· οὐαί σοι, Βηθσαϊδά· ὅτι εἰ ἐν Τύρῳ καὶ Σιδῶνι ἐγενήθησαν αἱ δυνάμεις αἱ γενόμεναι ἐν ὑμῖν, πάλαι ἂν ἐν σάκκῳ καὶ σποδῷ καθήμεναι μετενόησαν.', 'Ouai soi, Chorazin; ouai soi, Bēthsaida; hoti ei en Turō kai Sidōni egenēthēsan hai dunameis hai genomenai en humin, palai an en sakkō kai spodō kathēmenai metenoesan.', 'Woes (ouai — laments/judgments) on Galilean cities that witnessed Jesus''s miracles but did not repent. Chorazin and Bethsaida were near Capernaum on the northern shore of Galilee; the miracles performed there are not specifically recorded in the Gospels but were apparently extensive. Tyre and Sidon were ancient Phoenician cities condemned by the prophets (Isa 23; Ezek 26-28) — pagan cities of proverbial wickedness. Yet they would have repented in sackcloth. The failure of religious familiarity is more culpable than the failure of pagan ignorance.', NULL),
  (14, 'But it shall be more tolerable for Tyre and Sidon at the judgment, than for you.', 'πλὴν Τύρῳ καὶ Σιδῶνι ἀνεκτότερον ἔσται ἐν τῇ κρίσει ἢ ὑμῖν.', 'plēn Turō kai Sidōni anektoteron estai en tē krisei ē humin.', '"At the judgment" (en tē krisei) — the final eschatological reckoning. The comparative "more tolerable" again implies differential judgment based on available light and response. This principle has profound pastoral implications: those who sit under faithful gospel preaching but remain unmoved bear greater responsibility than those who have never heard. Chorazin and Bethsaida had "the mighty works" (dunameis — miracles) as evidence; Tyre and Sidon had neither.', NULL),
  (15, 'And thou, Capernaum, which art exalted to heaven, shalt be thrust down to hell.', 'καὶ σύ, Καφαρναούμ, ἡ ἕως τοῦ οὐρανοῦ ὑψωθεῖσα, ἕως τοῦ ᾅδου καταβιβασθήσῃ.', 'kai su, Kapharnaum, hē heōs tou ouranou hupsōtheisa, heōs tou haidou katabibasthēsē.', '"Exalted to heaven" — Capernaum was the center of Jesus''s Galilean ministry, the site of the most miracles recorded in the Gospels. Its elevation was spiritual privilege, not merely geographic. "Thrust down to hell" (hadou — Hades, the realm of the dead, the place of the departed). The language echoes the taunt against Babylon (Isa 14:13-15: "I will ascend to heaven... thou shalt be brought down to Sheol"). The greater the honour, the greater the fall of rejection.', NULL),
  (16, 'He that heareth you heareth me; and he that despiseth you despiseth me; and he that despiseth me despiseth him that sent me.', 'Ὁ ἀκούων ὑμῶν ἐμοῦ ἀκούει· καὶ ὁ ἀθετῶν ὑμᾶς ἐμὲ ἀθετεῖ· ὁ δὲ ἐμὲ ἀθετῶν ἀθετεῖ τὸν ἀποστείλαντά με.', 'Ho akouōn humōn emou akouei; kai ho athetōn humas eme athetei; ho de eme athetōn athetei ton aposteilanta me.', 'The apostolic chain of identification: the messenger''s reception is the Lord''s reception; the messenger''s rejection is the Lord''s rejection; the Lord''s rejection is the Father''s rejection. "Despiseth" (athetōn — sets aside, nullifies, treats as invalid). The word is used for setting aside a legal contract. To dismiss the apostles'' message is to legally nullify the claims of both the Son and the Father. This gives apostolic preaching its ultimate weight and authority.', NULL),
  (17, 'And the seventy returned again with joy, saying, Lord, even the devils are subject unto us through thy name.', 'Ὑπέστρεψαν δὲ οἱ ἑβδομήκοντα μετὰ χαρᾶς λέγοντες, Κύριε, καὶ τὰ δαιμόνια ὑποτάσσεται ἡμῖν ἐν τῷ ὀνόματί σου.', 'Hupestrepsan de hoi hebdomēkonta meta charas legontes, Kurie, kai ta daimonia hupotassetai hēmin en tō onomati sou.', '"With joy" (meta charas) — the return is celebratory. They had expected to preach; they discovered they had authority over demons. "Through thy name" (en tō onomati sou) — the authority is explicitly derived, not inherent. They do not say "we have power over demons"; they say "through your name they are subject to us." The name of Jesus is the operative authority, not the disciples'' personal spiritual credentials.', NULL),
  (18, 'And he said unto them, I beheld Satan as lightning fall from heaven.', 'εἶπεν δὲ αὐτοῖς, Ἐθεώρουν τὸν Σατανᾶν ὡς ἀστραπὴν ἐκ τοῦ οὐρανοῦ πεσόντα.', 'eipen de autois, Etheorun ton Satanan hōs astrapen ek tou ouranou pesonta.', '"I beheld Satan as lightning fall from heaven" — a visionary declaration, not necessarily a reference to the primordial fall of Isaiah 14 (though that may inform the imagery), but to the ongoing defeat of Satan''s kingdom through the disciples'' mission. Each exorcism is a skirmish in the cosmic war; Jesus sees the aggregate effect: Satan''s kingdom losing its heavenly footing. The lightning imagery suggests speed, brightness, and finality. The cross will complete this defeat (John 12:31; Col 2:15).', NULL),
  (19, 'Behold, I give unto you power to tread on serpents and scorpions, and over all the power of the enemy: and nothing shall by any means hurt you.', 'ἰδοὺ δέδωκα ὑμῖν τὴν ἐξουσίαν τοῦ πατεῖν ἐπάνω ὄφεων καὶ σκορπίων, καὶ ἐπὶ πᾶσαν τὴν δύναμιν τοῦ ἐχθροῦ· καὶ οὐδὲν ὑμᾶς οὐ μὴ ἀδικήσῃ.', 'idou dedōka humin tēn exousian tou patein epanō opheōn kai skorpiōn, kai epi pasan tēn dunamin tou echthrou; kai ouden humas ou mē adikēsē.', '"Serpents and scorpions" — symbols of demonic danger and hostile powers (Ps 91:13; Isa 11:8). The authority to "tread upon" them echoes Genesis 3:15 (the heel that crushes the serpent''s head) and points to the Messiah''s ultimate victory. "Over all the power of the enemy" (pasan tēn dunamin tou echthrou — the entire power of the enemy). "Nothing shall hurt you" — not a promise of physical immunity but of spiritual invincibility in kingdom mission.', NULL),
  (20, 'Notwithstanding in this rejoice not, that the spirits are subject unto you; but rather rejoice, because your names are written in heaven.', 'πλὴν ἐν τούτῳ μὴ χαίρετε, ὅτι τὰ πνεύματα ὑμῖν ὑποτάσσεται· χαίρετε δὲ ὅτι τὰ ὀνόματα ὑμῶν ἐγγέγραπται ἐν τοῖς οὐρανοῖς.', 'plēn en toutō mē chairete, hoti ta pneumata humin hupotassetai; chairete de hoti ta onomata humōn engegraptai en tois ouranois.', 'The decisive redirection of kingdom joy. "Rejoice not in this" — ministry success, however real and wonderful, is not the foundation of Christian joy. "Rejoice because your names are written in heaven" — the perfect tense (engegraptai — has been written and stands written) indicates a permanent, irrevocable registration. The Book of Life (Rev 3:5; 20:12; 21:27). Joy grounded in election and redemption is independent of ministry outcomes; it cannot be taken away by failure, opposition, or death.', NULL),
  (21, 'In that hour Jesus rejoiced in spirit, and said, I thank thee, O Father, Lord of heaven and earth, that thou hast hid these things from the wise and prudent, and hast revealed them unto babes: even so, Father; for so it seemed good in thy sight.', 'Ἐν αὐτῇ τῇ ὥρᾳ ἠγαλλιάσατο ἐν τῷ Πνεύματι τῷ ἁγίῳ, καὶ εἶπεν, Ἐξομολογοῦμαί σοι, Πάτερ, Κύριε τοῦ οὐρανοῦ καὶ τῆς γῆς, ὅτι ἀπέκρυψας ταῦτα ἀπὸ σοφῶν καὶ συνετῶν, καὶ ἀπεκάλυψας αὐτὰ νηπίοις· ναί, ὁ Πατήρ, ὅτι οὕτως εὐδοκία ἐγένετο ἔμπροσθέν σου.', 'En autē tē hōra ēgalliasato en tō Pneumati tō hagiō, kai eipen, Exomologoumai soi, Pater, Kurie tou ouranou kai tēs gēs, hoti apekrupsas tauta apo sophōn kai sunetōn, kai apekalupsas auta nēpiois; nai, ho Patēr, hoti houtōs eudokia egeneto emprosthen sou.', '"Jesus rejoiced in spirit" (ēgalliasato — exulted, leaped with joy) — Luke uniquely records Jesus''s jubilation. It is the most explicit expression of Jesus''s own emotional delight in the Gospels. "In the Holy Spirit" — the joy is Spirit-prompted. He thanks the Father for the sovereign mystery of revelation: hidden from the "wise and prudent" (those who trust in their own intellectual and religious resources), revealed to "babes" (nēpiois — infants, the humble, the unlearned). The sovereign pleasure of the Father (eudokia — good pleasure, gracious will) is the ultimate explanation.', NULL),
  (22, 'All things are delivered to me of my Father: and no man knoweth who the Son is, but the Father; and who the Father is, but the Son, and he to whom the Son will reveal him.', 'Πάντα μοι παρεδόθη ὑπὸ τοῦ Πατρός μου· καὶ οὐδεὶς γινώσκει τίς ἐστιν ὁ Υἱὸς εἰ μὴ ὁ Πατήρ, καὶ τίς ἐστιν ὁ Πατὴρ εἰ μὴ ὁ Υἱὸς καὶ ᾧ ἐὰν βούλητai ὁ Υἱὸς ἀποκαλύψαι.', 'Panta moi paredothē hupo tou Patros mou; kai oudeis ginōskei tis estin ho Huios ei mē ho Patēr, kai tis estin ho Patēr ei mē ho Huios kai hō ean boulētai ho Huios apokalupsai.', '"All things are delivered to me of my Father" — a comprehensive claim to universal authority and inheritance. The mutual knowledge of Father and Son is exclusive and reciprocal: only the Father truly knows the Son''s identity; only the Son truly knows the Father. This is sometimes called the "Johannine bolt" in the Synoptics — its content is characteristic of John''s Gospel (1:18; 17:25). It establishes that knowledge of God is Christologically mediated: only through the Son''s revelation is the Father known.', NULL),
  (23, 'And he turned him unto his disciples, and said privately, Blessed are the eyes which see the things that ye see:', 'Καὶ στραφεὶς πρὸς τοὺς μαθητὰς κατ'' ἰδίαν εἶπεν, Μακάριοι οἱ ὀφθαλμοὶ οἱ βλέποντες ἃ βλέπετε·', 'Kai strapheis pros tous mathētas kat'' idian eipen, Makarioi hoi ophthalmoi hoi blepontes ha blepete;', '"Privately" (kat'' idian) — Jesus turns from the public praise to a private beatitude for the disciples. "Blessed are the eyes" — a beatitude of privilege. The disciples are witnesses to what countless faithful people longed to see but died without seeing. The passive recipients of revelation are declared blessed — not for their own merit but for their participation in the kairos moment of history.', NULL),
  (24, 'For I tell you, that many prophets and kings have desired to see those things which ye see, and have not seen them; and to hear those things which ye hear, and have not heard them.', 'λέγω γὰρ ὑμῖν ὅτι πολλοὶ προφῆται καὶ βασιλεῖς ἠθέλησαν ἰδεῖν ἃ ὑμεῖς βλέπετε, καὶ οὐκ εἶδαν· καὶ ἀκοῦσαι ἃ ἀκούετε, καὶ οὐκ ἤκουσαν.', 'legō gar humin hoti polloi prophētai kai basileis ēthelēsan idein ha humeis blepete, kai ouk eidan; kai akousai ha akouete, kai ouk ēkousan.', '"Prophets and kings" — the most distinguished figures of the OT age. Abraham "saw" Christ''s day from afar and rejoiced (John 8:56); David prophesied of his Lord''s resurrection (Acts 2:25-31); Isaiah saw the glory (John 12:41). They saw by faith and prophecy; the disciples saw with physical eyes. The fulfilment of OT hope is the privilege of the disciples'' generation. This is the theological climax of the mission section: what the seventy witnessed in their successful ministry was the fruit of millennia of prophetic anticipation.', NULL),
  (25, 'And, behold, a certain lawyer stood up, and tempted him, saying, Master, what shall I do to inherit eternal life?', 'Καὶ ἰδοὺ νομικός τις ἀνέστη ἐκπειράζων αὐτὸν λέγων, Διδάσκαλε, τί ποιήσας ζωὴν αἰώνιον κληρονομήσω;', 'Kai idou nomikos tis anestē ekpeirazōn auton legōn, Didaskale, ti poiēsas zōēn aiōnion klēronomēsō?', '"A certain lawyer" (nomikos — an expert in Torah, a scribe). "Tempted him" (ekpeirazōn — testing, attempting to entrap). The question "what shall I do to inherit eternal life?" is sincere in form but adversarial in intent. Note the embedded theological assumption: he frames it as something to be "done" — earned. Jesus''s response will use the lawyer''s own Torah expertise to show him both the answer and his failure to live it.', NULL),
  (26, 'He said unto him, What is written in the law? how readest thou?', 'ὁ δὲ εἶπεν πρὸς αὐτόν, Ἐν τῷ νόμῳ τί γέγραπται; πῶς ἀναγινώσκεις;', 'ho de eipen pros auton, En tō nomō ti gegraptai? pōs anaginōskeis?', '"How readest thou?" — Jesus uses the lawyer''s own expertise as the instrument of instruction. Rather than providing an authoritative answer directly, he asks the expert to supply what he already knows. This Socratic approach forces the lawyer to own the answer before it convicts him. "What is written" (ti gegraptai — perfect: what stands written) — the permanent, authoritative Scripture.', NULL),
  (27, 'And he answering said, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy strength, and with all thy mind; and thy neighbour as thyself.', 'ὁ δὲ ἀποκριθεὶς εἶπεν, Ἀγαπήσεις Κύριον τὸν Θεόν σου ἐξ ὅλης τῆς καρδίας σου καὶ ἐξ ὅλης τῆς ψυχῆς σου καὶ ἐξ ὅλης τῆς ἰσχύος σου καὶ ἐξ ὅλης τῆς διανοίας σου, καὶ τὸν πλησίον σου ὡς σεαυτόν.', 'ho de apokritheis eipen, Agapēseis Kurion ton Theon sou ex holēs tēs kardias sou kai ex holēs tēs psuchēs sou kai ex holēs tēs ischuos sou kai ex holēs tēs dianoias sou, kai ton plēsion sou hōs seauton.', 'The lawyer correctly summarizes the whole Law: Deuteronomy 6:5 (the Shema — love of God) + Leviticus 19:18 (love of neighbour). The four-fold exhaustive love of God (heart, soul, strength, mind) describes love that leaves no compartment of the self uncommitted. The combination of the two commandments is confirmed by Jesus in 20:27 (Mark 12:29-31) as the summary of all Torah. The lawyer''s answer is theologically impeccable — and spiritually impossible without grace.', NULL),
  (28, 'And he said unto him, Thou hast answered right: this do, and thou shalt live.', 'εἶπεν δὲ αὐτῷ, Ὀρθῶς ἀπεκρίθης· τοῦτο ποίει καὶ ζήσῃ.', 'eipen de autō, Orthōs apekrithēs; touto poiei kai zēsē.', '"Thou hast answered right" (Orthōs apekrithēs) — Jesus commends the answer. "This do, and thou shalt live" — the conditional clause is the whole problem. The lawyer knows the law; the question is whether he lives it. Jesus is not offering a works-righteousness path to salvation but exposing the lawyer''s actual situation: you know what is required; are you doing it? The follow-up question (v.29) reveals that the lawyer already knows the answer.', NULL),
  (29, 'But he, willing to justify himself, said unto Jesus, And who is my neighbour?', 'ὁ δὲ θέλων δικαιῶσαι ἑαυτόν, εἶπεν πρὸς τὸν Ἰησοῦν, Καὶ τίς ἐστίν μου πλησίον;', 'ho de thelōn dikaiōsai heauton, eipen pros ton Iēsoun, Kai tis estin mou plēsion?', '"Willing to justify himself" (thelōn dikaiōsai heauton) — a crucial psychological disclosure. He senses his failure at the love-of-God standard and seeks to limit the scope of "neighbour" to make his compliance plausible. "Who is my neighbour?" — asking for a definition that will permit exclusion: who qualifies? Who can I legitimately ignore? Jesus''s parable will invert the question entirely: not "who must I love?" but "are you being the neighbour the situation requires?"', NULL),
  (30, 'And Jesus answering said, A certain man went down from Jerusalem to Jericho, and fell among thieves, which stripped him of his raiment, and wounded him, and departed, leaving him half dead.', 'ὑπολαβὼν δὲ ὁ Ἰησοῦς εἶπεν, Ἄνθρωπός τις κατέβαινεν ἀπὸ Ἱερουσαλὴμ εἰς Ἰεριχώ, καὶ λῃσταῖς περιέπεσεν, οἳ καὶ ἐκδύσαντες αὐτὸν καὶ πληγὰς ἐπιθέντες ἀπῆλθον, ἀφέντες ἡμιθανῆ τυγχάνοντα.', 'hupolabōn de ho Iēsous eipen, Anthrōpos tis katebaine apo Hierousalēm eis Ierichos, kai lēstais periesepsen, hoi kai ekdusantes auton kai plegas epithentes apēlthen, aphentes hēmithanē tunchanonta.', 'The Jerusalem-Jericho road descended 3,300 feet in 17 miles through barren, rocky wilderness — notoriously dangerous (Jerome called it "the bloody way"). The traveler is unnamed: no ethnic or religious identity is assigned, making him representative of any human being in need. "Stripped him, wounded him, half dead" — three stages of complete vulnerability. Stripped: no identity markers left. Wounded: physically broken. Half dead: beyond self-rescue.', NULL),
  (31, 'And by chance there came down a certain priest that way: and when he saw him, he passed by on the other side.', 'κατὰ συγκυρίαν δὲ ἱερεύς τις κατέβαινεν ἐν τῇ ὁδῷ ἐκείνῃ· καὶ ἰδὼν αὐτὸν ἀντιπαρῆλθεν.', 'kata sunkurian de hiereus tis katebaine en tē hodō ekeinē; kai idōn auton antiparēlthen.', '"By chance" (kata sunkurian — by coincidence). The priest "saw him" (idōn) — he looked, perceived, and still "passed by on the other side" (antiparēlthen — crossed to the opposite side of the road). The priest had a rationale: if the man was dead, contact would render him unclean for temple service (Lev 21:1-4); and priestly duties in Jerusalem had to be protected. The law-keeper''s law became an excuse for lawlessness in the one commandment that superseded the ritual: love of neighbour.', NULL),
  (32, 'And likewise a Levite, when he was at the place, came and looked on him, and passed by on the other side.', 'ὁμοίως δὲ καὶ Λευΐτης γενόμενος κατὰ τὸν τόπον, ἐλθὼν καὶ ἰδὼν ἀντιπαρῆλθεν.', 'homoiōs de kai Leuitēs genomenos kata ton topon, elthōn kai idōn antiparēlthen.', 'The Levite "came and looked" — he went further than the priest (closer to the man) but still "passed by on the other side." He had even less ritual justification than the priest. Both religious professionals — the very people the law-expert expected to serve as positive examples — pass by. Their failure is not attributed to malice but to a failure of compassion in the face of obligation. The audience expected a third figure to be an Israelite layman; Jesus instead introduces a Samaritan.', NULL),
  (33, 'But a certain Samaritan, as he journeyed, came where he was: and when he saw him, he had compassion on him,', 'Σαμαρείτης δέ τις ὁδεύων ἦλθεν κατ'' αὐτὸν, καὶ ἰδὼν αὐτὸν ἐσπλαγχνίσθη,', 'Samareitēs de tis hodeuōn ēlthen kat'' auton, kai idōn auton esplanchnisthē,', 'The shocking reversal: the hero of the story is the despised Samaritan — the very people the disciples had wanted to incinerate (9:54), the people who had refused Jesus passage (9:53). "He had compassion" (esplanchnisthē — the visceral compassion of the bowels, the same word used of Jesus in 7:13). The Samaritan "also saw" the man (idōn — the same verb used of the priest and Levite), but where they saw and passed by, he saw and was moved. Compassion is the difference between seeing and acting.', NULL),
  (34, 'And went to him, and bound up his wounds, pouring in oil and wine, and set him on his own beast, and brought him to an inn, and took care of him.', 'καὶ προσελθὼν κατέδησεν τὰ τραύματα αὐτοῦ, ἐπιχέων ἔλαιον καὶ οἶνον· ἐπιβιβάσας δὲ αὐτὸν ἐπὶ τὸ ἴδιον κτῆνος ἤγαγεν αὐτὸν εἰς πανδοχεῖον καὶ ἐπεμελήθη αὐτοῦ.', 'kai proselthōn katedeesen ta traumata autou, epicheon elaion kai oinon; epibibasas de auton epi to idion ktēnos ēgagen auton eis pandocheion kai epemelēthē autou.', 'Six acts of costly care: (1) went to him — crossed the social boundary; (2) bound his wounds; (3) poured oil and wine — standard ancient medicines, from his own supplies; (4) set him on his own beast — walked himself; (5) brought him to an inn; (6) took care of him through the night. Each action is concrete, specific, and costly. The Samaritan gave his time, his materials, his animal, and his money. Love is not sentiment; it is specific, costly action.', NULL),
  (35, 'And on the morrow when he departed, he took out two pence, and gave them to the host, and said unto him, Take care of him; and whatsoever thou spendest more, when I come again, I will repay thee.', 'καὶ ἐπὶ τὴν αὔριον ἐκβαλὼν ἔδωκεν δύο δηνάρια τῷ πανδοχεῖ, καὶ εἶπεν, Ἐπιμελήθητι αὐτοῦ· καὶ ὅ τι ἂν προσδαπανήσῃς, ἐγὼ ἐν τῷ ἐπανέρχεσθαί με ἀποδώσω σοι.', 'kai epi tēn aurion ekbalōn edōken duo dēnaria tō pandochei, kai eipen, Epimelēthēti autou; kai hoti an prosdapanēsēs, egō en tō epanercheesthai me apodōsō soi.', '"Two pence" (duo dēnaria — two days'' wages), enough for several weeks'' lodging. "Whatsoever thou spendest more, I will repay" — an open-ended financial commitment to a stranger''s welfare. The Samaritan''s generosity has no upper limit: he trusts the innkeeper to spend what is needed and commits to cover whatever additional cost arises on his return. This is extravagant, overflowing generosity — the character of God himself toward sinners.', NULL),
  (36, 'Which now of these three, thinkest thou, was neighbour unto him that fell among the thieves?', 'τίς τούτων τῶν τριῶν πλησίον δοκεῖ σοι γεγονέναι τοῦ ἐμπεσόντος εἰς τοὺς λῃστάς;', 'tis toutōn tōn triōn plēsion dokei soi gegonenai tou empesontos eis tous lēstas?', 'The question inverts the lawyer''s original question. He asked "who is my neighbour?" — seeking to define the limits of obligation. Jesus asks "which one became a neighbour?" — asking about action rather than status. The neighbour is not defined by proximity, ethnicity, or religion but by the act of compassionate service. The lawyer must answer out of his own mouth — and in doing so, must name the Samaritan (though note he cannot bring himself to say the name in v.37: "he that shewed mercy").', NULL),
  (37, 'And he said, He that shewed mercy on him. Then said Jesus unto him, Go, and do thou likewise.', 'ὁ δὲ εἶπεν, Ὁ ποιήσας τὸ ἔλεος μετ'' αὐτοῦ. εἶπεν δὲ αὐτῷ ὁ Ἰησοῦς, Πορεύου καὶ σὺ ποίει ὁμοίως.', 'ho de eipen, Ho poiēsas to eleos met'' autou. eipen de autō ho Iēsous, Poreuou kai su poiei homoiōs.', '"He that shewed mercy" (ho poiēsas to eleos — the one who did mercy). The lawyer cannot bring himself to say "the Samaritan." But he has answered correctly. "Go, and do thou likewise" (Poreuou kai su poiei homoiōs) — five words in Greek that constitute the most direct and demanding ethical command of the Sermon section. The parable was not merely illustrative but imperative: go and act as the Samaritan acted, regardless of the victim''s identity. Mercy has no ethnic preconditions.', NULL),
  (38, 'Now it came to pass, as they went, that he entered into a certain village: and a certain woman named Martha received him into her house.', 'Ἐγένετο δὲ ἐν τῷ πορεύεσθαι αὐτοὺς καὶ αὐτὸς εἰσῆλθεν εἰς κώμην τινά· γυνὴ δέ τις ὀνόματι Μάρθα ὑπεδέξατο αὐτὸν εἰς τὴν οἰκίαν αὐτῆς.', 'Egeneto de en tō poreuesthai autous kai autos eisēlthen eis kōmēn tina; gunē de tis onomati Martha hupedexato auton eis tēn oikian autēs.', 'The village is not named here, but John 11:1 identifies Bethany as the home of Mary, Martha, and Lazarus. "Received him" (hupedexato — welcomed as a guest, the same verb used for Zacchaeus in 19:6). Martha takes initiative in hospitality — she is the householder, the one who "received" Jesus. Her service (diakonia, v.40) is honored in Luke as an essential form of discipleship. The problem is not the service but its proportion.', NULL),
  (39, 'And she had a sister called Mary, which also sat at Jesus'' feet, and heard his word.', 'καὶ τῇδε ἦν ἀδελφὴ καλουμένη Μαρία, ἣ καὶ παρακαθίσασα παρὰ τοὺς πόδας τοῦ Ἰησοῦ ἤκουεν τὸν λόγον αὐτοῦ.', 'kai tēde ēn adelphē kaloumenē Maria, hē kai parakathisasa para tous podas tou Iēsou ēkouen ton logon autou.', '"Sat at Jesus'' feet" (parakathisasa para tous podas) — the posture of a disciple receiving Torah from a rabbi (cf. Paul "at the feet of Gamaliel," Acts 22:3). In the first century, women did not typically sit at a rabbi''s feet to be taught; Mary''s posture is itself radical — she claims the right of discipleship. "Heard his word" (ēkouen ton logon — imperfect: was continuously hearing). She is the good-soil hearer of 8:15: one who hears and keeps the word.', NULL),
  (40, 'But Martha was cumbered about much serving, and came to him, and said, Lord, dost thou not care that my sister hath left me to serve alone? bid her therefore that she help me.', 'ἡ δὲ Μάρθα περιεσπᾶτο περὶ πολλὴν διακονίαν· ἐπιστᾶσα δὲ εἶπεν, Κύριε, οὐ μέλει σοί ὅτι ἡ ἀδελφή μου μόνην με κατέλιπεν διακονεῖν; εἰπὲ οὖν αὐτῇ ἵνα μοι συναντιλάβηται.', 'hē de Martha periespato peri pollēn diakonian; epistasa de eipen, Kurie, ou melei soi hoti hē adelphē mou monēn me katelipen diakonein? eipe oun autē hina moi sunantilabētai.', '"Cumbered about" (periespato — distracted, pulled in all directions). The word is vivid: Martha was being yanked around by many tasks. "Much serving" (pollēn diakonian) — the word is noble (diakonia), but "much" indicates it had become excessive and anxiety-producing. Her appeal to Jesus — "dost thou not care?" — is a mild accusation. She wants Jesus to adjudicate the domestic dispute in her favor. But in coming to Jesus with her complaint, she has done what Mary had done — she has come to his feet.', NULL),
  (41, 'And Jesus answered and said unto her, Martha, Martha, thou art careful and troubled about many things:', 'ἀποκριθεὶς δὲ εἶπεν αὐτῇ ὁ Κύριος, Μάρθα Μάρθα, μεριμνᾷς καὶ τυρβάζῃ περὶ πολλά,', 'apokritheis de eipen autē ho Kurios, Martha Martha, merimnas kai turbazetai peri polla,', '"Martha, Martha" — the doubled name is an address of tender rebuke (cf. "Simon, Simon" in 22:31; "Saul, Saul" in Acts 9:4). It is a gentle, loving correction. "Thou art careful and troubled" (merimnās — anxious; turbazetai — disturbed, unsettled). The two verbs describe both the internal state (anxiety) and the resulting disturbance. "About many things" (peri polla) — the multiplicity is the problem. Service has fragmented her attention into an anxious scatter.', NULL),
  (42, 'But one thing is needful: and Mary hath chosen that good part, which shall not be taken away from her.', 'ἑνὸς δέ ἐστιν χρεία· Μαριὰμ γὰρ τὴν ἀγαθὴν μερίδα ἐξελέξατο, ἥτις οὐκ ἀφαιρεθήσεται αὐτῆς.', 'henos de estin chreia; Mariam gar tēn agathēn merida exelexato, hētis ouk aphairethēsetai autēs.', '"One thing is needful" (henos de estin chreia — but of one thing there is need). The "one thing" is not identified as Mary''s behavior in isolation but as the principle it represents: hearing the word of Jesus has priority over all other activity. "Mary hath chosen that good part" (tēn agathēn merida — the good portion/share). "Which shall not be taken away from her" (ouk aphairethēsetai — future passive: will absolutely not be taken away). The word received and held is permanent; hospitality arrangements are temporary. This is the chapter''s final word: the foundation of all mission and service is sitting at the feet of Jesus and hearing his word.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 10;

-- ═══════════════════════════════════════════════════
-- LUKE CHAPTER 10 — BACKFILL: Word Studies + Cross References
-- ═══════════════════════════════════════════════════

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἑβδομήκοντα', 'hebdomēkonta', 'G1440', 'Seventy — (many MSS read "seventy-two"). Echoes Moses''s 70 elders (Num 11:16-25) and the 70 nations of Gen 10. Luke signals a mission beyond Israel: the gospel to the whole known world.', 1),
  (2, 'ἐργάτας', 'ergatas', 'G2040', 'Labourers — workers, not hirelings. The harvest metaphor demands kingdom workers willing to labour. Prayer precedes mission: ask the Lord of the harvest first.', 2),
  (3, 'ἀρνία ἐν μέσῳ λύκων', 'arnia en mesō lykōn', 'G704/G3074', 'Lambs in the midst of wolves — the church''s vulnerability in a hostile world. No armour is promised — only the protection of the Sender himself.', 3),
  (4, 'βαλάντιον', 'balantion', 'G905', 'Purse — money-bag. Radical travel-light instructions enforce dependence on God via the hospitality of hearers (cf. 22:35 review).', 4),
  (5, 'εἰρήνη τῷ οἴκῳ τούτῳ', 'eirēnē tō oikō toutō', 'G1515', 'Peace to this house — the Semitic greeting shalom carries substantive blessing, not mere politeness. A "son of peace" = one receptive to the gospel''s peace.', 5),
  (7, 'ἄξιος ὁ ἐργάτης τοῦ μισθοῦ', 'axios ho ergatēs tou misthou', 'G514/G3408', 'The labourer is worthy of his hire — quoted by Paul as "Scripture" (1 Tim 5:18), one of the earliest NT sayings to attain canonical status. Ministry support is a kingdom principle, not a concession.', 6),
  (9, 'ἤγγικεν ἡ βασιλεία', 'ēngiken hē basileia', 'G1448/G932', 'The kingdom has come near — perfect tense: has drawn near and now stands near. Whether by reception or rejection, proximity brings crisis.', 7),
  (11, 'τὸν κονιορτὸν ἀπομασσόμεθα', 'ton koniorton apomassometha', 'G2868/G631', 'We wipe off the dust — prophetic sign-act (cf. 9:5; Acts 13:51). The rejecting town is classed with pagan territory; even contact-defilement is removed.', 8),
  (15, 'ἕως ᾅδου', 'heōs hadou', 'G2193/G86', 'Down to hades — echoing Isaiah''s taunt against Babylon''s king (Isa 14:13-15). Capernaum''s privileged exposure to Jesus incurs correspondingly severe judgment.', 9),
  (16, 'ὁ ἀκούων ὑμῶν ἐμοῦ ἀκούει', 'ho akouōn hymōn emou akouei', 'G191', 'He that heareth you heareth me — apostolic shaliach principle: the sent-one represents the sender with full force. Rejecting the apostle = rejecting Christ = rejecting the Father.', 10),
  (17, 'ὑπέστρεψαν οἱ ἑβδομήκοντα', 'hypestrepsan hoi hebdomēkonta', 'G5290', 'The seventy returned — with joy. Their testimony: "even the demons are subject to us in thy name." The name of Jesus is authoritative over the unseen world.', 11),
  (18, 'Σατανᾶν ὡς ἀστραπὴν πεσόντα', 'Satanan hōs astrapēn pesonta', 'G4567/G796', 'Satan fall as lightning — the cosmic consequence of kingdom advance. Each local deliverance is a piece of Satan''s eschatological downfall (cf. Rev 12:9).', 12),
  (19, 'ἐξουσίαν τοῦ πατεῖν ἐπάνω ὄφεων', 'exousian tou patein epanō opheōn', 'G1849/G3961/G3789', 'Authority to tread on serpents — echoing Ps 91:13 and Gen 3:15 (the seed crushing the serpent). Delegated power over all demonic hostility.', 13),
  (20, 'τὰ ὀνόματα ὑμῶν ἐγγέγραπται', 'ta onomata hymōn engegraptai', 'G1449', 'Your names are written — perfect passive: have been inscribed and stand inscribed. Book-of-life image (Exod 32:32; Rev 21:27). Eternal acceptance outranks spiritual gifting as cause for joy.', 14),
  (21, 'ἠγαλλιάσατο τῷ πνεύματι τῷ ἁγίῳ', 'ēgalliasato tō pneumati tō hagiō', 'G21', 'Rejoiced in the Holy Spirit — Luke alone connects Jesus''s rejoicing to the Spirit. A rare window into Jesus''s emotional/Trinitarian life.', 15),
  (21, 'νηπίοις', 'nēpiois', 'G3516', 'Babes — infants, little ones. The Father''s sovereign pleasure in bypassing the "wise and prudent" to reveal himself to the simple and humble.', 16),
  (22, 'οὐδεὶς γινώσκει τίς ἐστιν ὁ υἱός', 'oudeis ginōskei tis estin ho huios', 'G1097/G5207', 'No one knows who the Son is — the intra-Trinitarian mutual knowledge. Reciprocal, exclusive, exhaustive. One of the most Johannine sayings in the Synoptics.', 17),
  (25, 'νομικός', 'nomikos', 'G3544', 'Lawyer — a scribe specialising in Torah interpretation. His question about eternal life is a test (ekpeirazōn), not genuine inquiry.', 18),
  (25, 'ζωὴν αἰώνιον', 'zōēn aiōnion', 'G2222/G166', 'Eternal life — aiōnios = belonging to the age to come. Not merely unending duration but the quality of life in the messianic age.', 19),
  (27, 'ἀγαπήσεις Κύριον ἐξ ὅλης τῆς καρδίας', 'agapēseis Kurion ex holēs tēs kardias', 'G25', 'Love the Lord with all thy heart — the Shema (Deut 6:5). Jesus affirms the lawyer''s summary: love of God and neighbour is the essence of the whole Law.', 20),
  (29, 'δικαιῶσαι ἑαυτόν', 'dikaiōsai heauton', 'G1344', 'To justify himself — to vindicate his own righteousness. The lawyer''s follow-up ("who is my neighbour?") is an attempt to limit obligation.', 21),
  (30, 'λῃσταῖς', 'lēstais', 'G3027', 'Thieves / bandits — not petty thieves but violent brigands (same word used for Barabbas, 23:19). The Jericho road was notoriously dangerous.', 22),
  (33, 'Σαμαρείτης', 'Samaritēs', 'G4541', 'Samaritan — to the lawyer''s ear, an oxymoronic hero. Samaritans were hated half-breeds, religiously apostate (John 4:9). Jesus picks the most despised figure as moral exemplar.', 23),
  (33, 'ἐσπλαγχνίσθη', 'esplanchnisthē', 'G4697', 'Had compassion — from splagchna (inner organs, gut). A visceral, Hebraic compassion — the same verb used for Jesus''s own compassion (7:13). True neighbour-love begins in the gut.', 24),
  (34, 'ἔλαιον καὶ οἶνον', 'elaion kai oinon', 'G1637/G3631', 'Oil and wine — standard first-century wound-care: oil to soothe, wine (with alcohol) to disinfect. Not metaphorical but practical mercy at personal cost.', 25),
  (35, 'δύο δηνάρια', 'dyo dēnaria', 'G1417/G1220', 'Two denarii — two days'' wages for a labourer. Enough for roughly two months'' lodging at an inn. Extravagant generosity to a stranger.', 26),
  (37, 'ὁ ποιήσας τὸ ἔλεος', 'ho poiēsas to eleos', 'G4160/G1656', 'He that shewed mercy — the lawyer cannot even say the word "Samaritan." Jesus''s imperative: "go and do thou likewise" — mercy, not tribal boundary-drawing, defines neighbourliness.', 27),
  (39, 'παρακαθίσασα πρὸς τοὺς πόδας', 'parakathisasa pros tous podas', 'G3869/G4228', 'Sat at his feet — the formal posture of a disciple under a rabbi (cf. Paul at Gamaliel''s feet, Acts 22:3). Revolutionary: Mary takes the posture of a male disciple.', 28),
  (40, 'περιεσπᾶτο', 'periespato', 'G4049', 'Was cumbered — literally "pulled about in many directions." Imperfect: continually distracted. Martha''s service is good but fragmented and agitated.', 29),
  (41, 'μεριμνᾷς καὶ τυρβάζῃ', 'merimnas kai turbazē', 'G3309/G5182', 'Careful and troubled — merimnaō = anxious worry (the same word for the "cares" of 8:14 that choked the seed); turbazō = agitated, in turmoil.', 30),
  (42, 'ἑνὸς δέ ἐστιν χρεία', 'henos de estin chreia', 'G1520/G5532', 'One thing is needful — the priority of attentive hearing over busy serving. Service flows from sitting; sitting does not flow from service.', 31),
  (42, 'τὴν ἀγαθὴν μερίδα', 'tēn agathēn merida', 'G18/G3310', 'The good portion — meris = a share or portion allotted. Mary has chosen her inheritance; it "shall not be taken away" (future passive with double negative = absolute promise).', 32)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 10 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

